
(function(){
  const routes=[
    {id:'mission',title:'GoalOS Mission Autopilot',href:'goalos-mission-autopilot.html',why:'Turn one objective into Mission Contract, Evidence Docket outline, governed decision state, Action Graph, Chronicle entry, and receipt.'},
    {id:'evidence',title:'Evidence Docket Composer',href:'evidence-docket-composer.html',why:'Build the proof room before a public claim advances.'},
    {id:'until',title:'Until-DONE Mission Control',href:'until-done-mission-control.html',why:'Run objective → proof gates until every required artifact is present.'},
    {id:'rsi',title:'Loop → RSI Control Room',href:'loop-to-rsi-control-room.html',why:'Convert restartable loops into deterministic RSI governance with ECI, baselines, replay, dossier, and Chronicle.'},
    {id:'asi',title:'Superintelligence Proof Governance Console',href:'superintelligence-proof-governance-console.html',why:'Inspect the highest-assurance proof horizon with authority firewall, council review, capacity discipline, and human boundary.'},
    {id:'settlement',title:'Proof-Settlement Lifecycle',href:'proof-settlement-lifecycle.html',why:'Follow Request → Escrow → Execute → Proof → Validate → Settle → Chronicle without public funds movement.'},
    {id:'legal',title:'Legal / Data-Zero Boundary',href:'legal.html',why:'Confirm privacy, third-party, token, no-advice, no-wallet, and no-production-authority boundaries.'},
    {id:'all',title:'Complete Route Index',href:'complete-route-index.html',why:'Search every preserved public page, demo, proof room, console, and boundary surface.'},
    {id:'ask',title:'Ask GoalOS',href:'ask-goalos.html',why:'Ask a public-site question and receive a local route receipt.'}
  ];
  const terms={evidence:['evidence','docket','claim','proof','verify','source','audit','review','provenance'],rsi:['loop','rsi','recursive','invention','baseline','eci','move','dossier','restart','trace'],asi:['asi','superintelligence','horizon','council','authority','capacity','frontier'],settlement:['settle','settlement','escrow','job','proofbundle','fund','payment','chronicle'],legal:['legal','privacy','data','gdpr','regulation','investment','tax','wallet','token','boundary','responsibility'],all:['all pages','missing','where','find','navigate','route','catalog','start','begin']};
  const stages=['Read objective','Classify intent','Write mission contract','Select proof route','Draft Evidence Docket','Assign verifier mesh','Set decision state','Prepare route handoff','Package receipt'];
  const docket=['Manifest','Claims Matrix','Source Provenance','Proof Packets','Verifier Report','Risk Ledger','Replay Path','Decision State','Action Graph','Chronicle Entry'];
  const $=(s,r=document)=>r.querySelector(s); const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
  const esc=s=>String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const norm=s=>String(s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();
  let last=null;
  function classify(text){const n=norm(text);const score={evidence:0,rsi:0,asi:0,settlement:0,legal:0,all:0};for(const [k,arr] of Object.entries(terms)){for(const t of arr){if(n.includes(t))score[k]+=1;}}return score;}
  function pick(text){const s=classify(text);let ids=[];if(s.legal)ids.push('legal');if(s.asi)ids.push('asi','rsi','evidence');if(s.rsi)ids.push('rsi','evidence','until');if(s.settlement)ids.push('settlement','evidence','legal');if(s.evidence)ids.push('evidence','until','mission');if(s.all)ids.push('all','ask','mission');ids.push('mission','evidence','until','legal');ids=[...new Set(ids)];const route=ids.map(id=>routes.find(r=>r.id===id)).find(Boolean)||routes[0];const alternatives=ids.map(id=>routes.find(r=>r.id===id)).filter(Boolean).filter(r=>r.id!==route.id).slice(0,4);const confidence=Math.min(98,62+Math.max(...Object.values(s))*8+Object.values(s).reduce((a,b)=>a+b,0)*2);return {route,alternatives,confidence,score:s};}
  function build(text){const objective=String(text||'').trim();if(!objective)return null;const p=pick(objective);const risk=p.score.legal?'boundary-review':'public-safe';const verdict=p.confidence>82?'HUMAN_REVIEW_READY':'MISSION_DRAFT_READY';return {receiptType:'GoalOSCommandReceipt',version:'v64-command-console',generatedAt:new Date().toISOString(),objective,riskClass:risk,recommendedRoute:p.route,alternativeRoutes:p.alternatives,confidence:p.confidence,missionContract:{objective,successCriteria:['plain-language objective is converted into a bounded mission','claim and proof obligations are separated','safest public route is selected','human review boundary remains explicit'],blockedOperations:['wallet connection','token approval','network request from the console','form submission','browser storage','transaction broadcast','production authority','legal/financial/investment advice'],doneCondition:'human-review-ready proof package plus route handoff'},evidenceDocket:docket.map((name,i)=>({name,required:true,status:i<3?'drafted':'planned'})),verifierMesh:['claim boundary','evidence support','source/provenance reality','risk and privacy boundary','replay/readiness','human review'],decisionState:{verdict,productionAuthority:false,walletActions:false,networkRequests:false,userDataRetained:false},routeHandoff:{open:p.route.href,why:p.route.why},boundary:{publicSafe:true,noAccount:true,noFormSubmission:true,noWallet:true,noTokenApproval:true,noAnalytics:true,noCookies:true,noBrowserStorage:true,noNetworkRequest:true,noTransactionBroadcast:true,noProductionAuthority:true,noUserDataRetained:true}};}
  function addMessage(kind,html){const log=$('[data-chat-log]');if(!log)return;const art=document.createElement('article');art.className='gcmd-message '+kind;art.innerHTML=html;log.appendChild(art);log.scrollTop=log.scrollHeight;}
  function render(r){last=r;if(!r)return;const title=$('[data-route-title]');if(title)title.textContent=r.recommendedRoute.title;const reason=$('[data-route-reason]');if(reason)reason.textContent=r.recommendedRoute.why;const open=$('[data-route-open]');if(open){open.href=r.recommendedRoute.href;open.classList.remove('disabled');open.removeAttribute('aria-disabled');open.textContent='Open '+r.recommendedRoute.title+' →';}const conf=$('[data-confidence]');if(conf)conf.textContent=r.confidence+'%';const bar=$('[data-confidence-bar]');if(bar)bar.style.width=r.confidence+'%';const mt=$('[data-mission-title]');if(mt)mt.textContent=r.objective.length>88?r.objective.slice(0,85)+'…':r.objective;const cl=$('[data-contract-list]');if(cl)cl.innerHTML=r.missionContract.successCriteria.map(x=>'<li>'+esc(x)+'</li>').join('')+'<li><b>Done:</b> '+esc(r.missionContract.doneCondition)+'</li>';const dl=$('[data-docket-list]');if(dl)dl.innerHTML=r.evidenceDocket.map(x=>'<div><b>'+esc(x.name)+'</b><span>'+esc(x.status)+'</span></div>').join('');const vd=$('[data-verdict]');if(vd)vd.textContent=r.decisionState.verdict.replace(/_/g,' ');const pre=$('[data-receipt-preview]');if(pre)pre.textContent=JSON.stringify({receiptType:r.receiptType,version:r.version,recommendedRoute:r.recommendedRoute.href,confidence:r.confidence,boundary:r.boundary},null,2);}
  function run(text){const ta=$('[data-goalos-command]')||$('[data-home-command]');const objective=text||ta&&ta.value;const r=build(objective);if(!r)return;addMessage('user','<b>You</b><p>'+esc(r.objective)+'</p>');addMessage('system','<b>GoalOS</b><p>I composed a public-safe mission package, selected <strong>'+esc(r.recommendedRoute.title)+'</strong>, and prepared a local receipt. Nothing was sent anywhere.</p><a class="route-pill" href="'+esc(r.recommendedRoute.href)+'">Open route →</a>');render(r);renderHome(r);return r;}
  function renderHome(r){const el=$('[data-home-result]');if(!el||!r)return;el.innerHTML='<b>Recommended route:</b> <a href="'+esc(r.recommendedRoute.href)+'">'+esc(r.recommendedRoute.title)+'</a><br><span>'+esc(r.recommendedRoute.why)+'</span>';}
  function download(){const r=last||build(($('[data-goalos-command]')||$('[data-home-command]')||{}).value);if(!r)return;const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(r,null,2)],{type:'application/json'}));a.download='goalos-command-receipt-v64.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),800);}
  function copy(){const r=last||build(($('[data-goalos-command]')||$('[data-home-command]')||{}).value);if(!r)return;const txt='GoalOS Command Console v64\nObjective: '+r.objective+'\nRoute: '+r.recommendedRoute.title+' — '+r.recommendedRoute.href+'\nWhy: '+r.recommendedRoute.why+'\nBoundary: local public-safe guidance only; no wallet, no network request, no user data retained, no production authority.';if(navigator.clipboard&&navigator.clipboard.writeText)navigator.clipboard.writeText(txt).catch(()=>{});}
  function init(){ $$('[data-example]').forEach(b=>b.addEventListener('click',()=>{const t=$('[data-goalos-command]');if(t){t.value=b.getAttribute('data-example')||'';t.focus();}})); const rb=$('[data-command-run]'); if(rb)rb.addEventListener('click',()=>run()); const db=$('[data-command-download]'); if(db)db.addEventListener('click',download); const cb=$('[data-command-copy]'); if(cb)cb.addEventListener('click',copy); const hb=$('[data-home-run]'); if(hb)hb.addEventListener('click',()=>run(($('[data-home-command]')||{}).value)); const hcopy=$('[data-home-copy]'); if(hcopy)hcopy.addEventListener('click',copy); const initial=build(($('[data-goalos-command]')||{}).value); if(initial) render(initial);}
  window.GOALOS_COMMAND_CONSOLE_V64={build,pick,run,routes,stages};
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init); else init();
})();
